export interface WorkflowRunInput {
	cwd: string;
	idea: string;
	loops: number;
	modelPattern?: string;
	thinkingLevel?: string;
	onStatus?: (message: string | undefined) => void;
	onEvent?: (event: WorkflowProgressEvent) => void;
	/** T3 fix: Optional invocation override for testing. */
	invocation?: { command: string; args?: string[] };
}

export interface WorkflowRunResult {
	callDir: string;
	relativeCallDir: string;
	manifest: WorkflowManifest;
	latestScore?: number;
}

function stagePaths(cwd: string, record: StageRecord): { logPath: string; stderrPath: string } {
	return {
		logPath: path.resolve(cwd, record.logPath),
		stderrPath: path.resolve(cwd, record.stderrPath),
	};
}



function emitWorkflowEvent(
	onEvent: ((event: WorkflowProgressEvent) => void) | undefined,
	event: WorkflowProgressEvent,
): void {
	onEvent?.(event);
}

function mapPiStageEventToWorkflowEvent(options: {
	event: PiStageStreamEvent;
	relativeCallDir: string;
	requestedLoops: number;
	completedLoops: number;
	stageName: StageName;
	loopNumber?: number;
}): WorkflowProgressEvent | undefined {
	const { event, relativeCallDir, requestedLoops, completedLoops, stageName, loopNumber } = options;

	switch (event.type) {
		case "tool_execution_start":
			return {
				type: "tool_start",
				relativeCallDir,
				requestedLoops,
				completedLoops,
				stageName,
				loopNumber,
				message: `Tool ${event.toolName} started`,
				toolName: event.toolName,
			};
		case "tool_execution_end":
			return {
				type: "tool_end",
				relativeCallDir,
				requestedLoops,
				completedLoops,
				stageName,
				loopNumber,
				message: event.isError ? `Tool ${event.toolName} returned an error` : `Tool ${event.toolName} completed`,
				toolName: event.toolName,
				isError: event.isError,
			};
		default:
			return undefined;
	}
}

async function runManagedStage(options: {
	cwd: string;
	protectedRoots: string[];
	modelPattern?: string;
	thinkingLevel?: string;
	record: StageRecord;
	stageName: StageName;
	loopNumber?: number;
	requestedLoops: number;
	completedLoops: number;
	relativeCallDir: string;
	systemPrompt: string;
	userPrompt: string;
	manifest: WorkflowManifest;
	manifestPath: string;
	onStatus?: (message: string | undefined) => void;
	onEvent?: (event: WorkflowProgressEvent) => void;
	statusMessage: string;
	/** T3 fix: Optional invocation override for testing. */
	invocation?: { command: string; args?: string[] };
}): Promise<StageExecutionResult> {
	const {
		cwd,
		protectedRoots,
		modelPattern,
		thinkingLevel,
		record,
		stageName,
		loopNumber,
		requestedLoops,
		completedLoops,
		relativeCallDir,
		systemPrompt,
		userPrompt,
		manifest,
		manifestPath,
		onStatus,
		onEvent,
		statusMessage,
		invocation,
	} = options;
	markStageRunning(record);
	await saveManifest(manifestPath, manifest);
	onStatus?.(statusMessage);
	emitWorkflowEvent(onEvent, {
		type: "stage_started",
		relativeCallDir,
		requestedLoops,
		completedLoops,
		message: statusMessage,
		stageName,
		stageStatus: record.status,
		loopNumber,
	});

	try {
		const paths = stagePaths(cwd, record);
		const result = await runPiStage({
			cwd,
			model: modelPattern,
			thinkingLevel,
			systemPrompt,
			userPrompt,
			logPath: paths.logPath,
			stderrPath: paths.stderrPath,
			protectedRoots,
			invocation,
			onProgress: (detail) => {
				const message = buildStageStatusMessage(statusMessage, detail);
				onStatus?.(message);
				emitWorkflowEvent(onEvent, {
					type: "stage_progress",
					relativeCallDir,
					requestedLoops,
					completedLoops,
					message,
					stageName,
					stageStatus: record.status,
					loopNumber,
				});
			},
			onEvent: (event) => {
				const mappedEvent = mapPiStageEventToWorkflowEvent({
					event,
					relativeCallDir,
					requestedLoops,
					completedLoops,
					stageName,
					loopNumber,
				});
				if (mappedEvent) emitWorkflowEvent(onEvent, mappedEvent);
			},
		});
		markStageSuccess(record, result);
		await saveManifest(manifestPath, manifest);
		emitWorkflowEvent(onEvent, {
			type: "stage_completed",
			relativeCallDir,
			requestedLoops,
			completedLoops,
			message: `Stage completed: ${stageDisplayName(stageName)}${loopNumber ? ` (loop ${loopNumber}/${requestedLoops})` : ""}`,
			stageName,
			stageStatus: record.status,
			loopNumber,
		});
		return result;
	} catch (error) {
		markStageFailure(record, error);
		await saveManifest(manifestPath, manifest);
		emitWorkflowEvent(onEvent, {
			type: "stage_failed",
			relativeCallDir,
			requestedLoops,
			completedLoops,
			message: error instanceof Error ? error.message : String(error),
			stageName,
			stageStatus: record.status,
			loopNumber,
			isError: true,
		});
		throw error;
	}
}

export async function runIdeaRefinementWorkflow(input: WorkflowRunInput): Promise<WorkflowRunResult> {
	const { cwd, idea, loops, modelPattern, thinkingLevel, onStatus, onEvent, invocation } = input;
	const callNumber = await findNextCallNumber(path.join(cwd, "docs", "idea_refinement"));
	const workspace = await prepareCallWorkspace(cwd, callNumber);
	const relativeCallDir = toProjectRelativePath(cwd, workspace.callDir);
	const manifest = createInitialManifest({
		cwd,
		workspace,
		callNumber,
		requestedLoops: loops,
		model: modelPattern,
		thinkingLevel,
		assumptions: WORKFLOW_ASSUMPTIONS,
	});

	await writeMarkdownFile(workspace.rootFiles.idea, idea);
	await saveManifest(workspace.rootFiles.manifest, manifest);
	emitWorkflowEvent(onEvent, {
		type: "workflow_started",
		relativeCallDir,
		requestedLoops: loops,
		completedLoops: 0,
		message: `Workflow started in ${relativeCallDir}`,
	});

	let latestScore: number | undefined;

	try {
		const initialRandomNumber = generateRandomNumber();
		const directivePolicy: DirectivePolicy = determineDirectivePolicy(initialRandomNumber);
		manifest.initialRandomNumber = initialRandomNumber;
		manifest.directivePolicy = directivePolicy;
		await saveManifest(workspace.rootFiles.manifest, manifest);

		const bootstrapResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.bootstrap,
			stageName: "bootstrap",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: INITIAL_ARTIFACTS_SYSTEM_PROMPT,
			userPrompt: buildInitialArtifactsUserPrompt({
				cwd,
				workspace,
				randomNumber: initialRandomNumber,
				policy: directivePolicy,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Generating initial artifacts in ${relativeCallDir}`,
			invocation,
		});

		let sections: Record<string, string>;
		try {
			sections = extractMarkedSections(bootstrapResult.text, [
				"DIRECTIVE.md",
				"LEARNING.md",
				"CRITERIA.md",
				"DIAGNOSIS.md",
				"METRICS.md",
				"BACKLOG.md",
			]);
		} catch (parseError) {
			const rawPath = path.join(workspace.callDir, "bootstrap-raw.md");
			await writeMarkdownFile(rawPath, bootstrapResult.text);
			throw new Error(
				`Failed to extract bootstrap sections; raw text preserved at ${rawPath}. Cause: ${parseError instanceof Error ? parseError.message : String(parseError)}`,
			);
		}
		await writeMarkdownFile(workspace.rootFiles.directive, sections["DIRECTIVE.md"]);
		await writeMarkdownFile(workspace.rootFiles.learning, sections["LEARNING.md"]);
		await writeMarkdownFile(workspace.rootFiles.criteria, sections["CRITERIA.md"]);
		await writeMarkdownFile(workspace.rootFiles.diagnosis, sections["DIAGNOSIS.md"]);
		await writeMarkdownFile(workspace.rootFiles.metrics, sections["METRICS.md"]);
		await writeMarkdownFile(workspace.rootFiles.backlog, sections["BACKLOG.md"]);
		await saveManifest(workspace.rootFiles.manifest, manifest);

		for (let loopNumber = 1; loopNumber <= loops; loopNumber += 1) {
			const loopRandomNumber = generateRandomNumber();
			const loopDir = await ensureLoopDirectory(workspace, loopNumber);
			const loopEntry = createLoopEntry({
				cwd,
				loopNumber,
				randomNumber: loopRandomNumber,
				loopDir,
				logsDir: workspace.logsDir,
			});
			manifest.loops.push(loopEntry);
			await saveManifest(workspace.rootFiles.manifest, manifest);

			// Snapshot C7: capture before develop to detect material changes
			// C2 fix: Snapshot C7 captures project source (cwd), not extension source
			const snapshotBefore = await takeSnapshot(cwd, { scope: ["lib", "tests"], maxDepth: 6, maxFiles: 5000 });

			const developResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.develop,
				stageName: "develop",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: DEVELOPMENT_SYSTEM_PROMPT,
				userPrompt: buildDevelopmentUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
					randomNumber: loopRandomNumber,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: developing RESPONSE.md`,
				invocation,
			});
			await writeMarkdownFile(workspace.rootFiles.response, developResult.text);
			await writeMarkdownFile(path.join(loopDir, "RESPONSE.md"), developResult.text);

			// Snapshot C7: compare before/after and store diff in loopEntry
			// C2 fix: Snapshot C7 after develop also uses cwd (project root)
			const snapshotAfter = await takeSnapshot(cwd, { scope: ["lib", "tests"], maxDepth: 6, maxFiles: 5000 });
			const c7Diff: SnapshotDiff = diffSnapshots(snapshotBefore, snapshotAfter);
			loopEntry.c7Snapshot = {
				hasChanges: c7Diff.hasChanges,
				diffSummary: formatSnapshotDiff(c7Diff),
				changedFiles: c7Diff.changed.length + c7Diff.added.length,
			};

			// If C7=0 (no material changes), emit WARNING notification
			if (!c7Diff.hasChanges) {
				const warningMsg = `⚠ Loop ${loopNumber}/${loops}: C7=0 — no material changes to source code after develop. This indicates pseudo-execution.`;
				onStatus?.(warningMsg);
				emitWorkflowEvent(onEvent, {
					type: "stage_progress",
					relativeCallDir,
					requestedLoops: loops,
					completedLoops: manifest.completedLoops,
					message: warningMsg,
					stageName: "develop",
					stageStatus: "running",
					loopNumber,
				});
			}

			const evaluateResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.evaluate,
				stageName: "evaluate",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: EVALUATION_SYSTEM_PROMPT,
				userPrompt: buildEvaluationUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: evaluating FEEDBACK.md`,
				invocation,
			});
			await writeMarkdownFile(workspace.rootFiles.feedback, evaluateResult.text);
			await writeMarkdownFile(path.join(loopDir, "FEEDBACK.md"), evaluateResult.text);

			loopEntry.score = extractOverallScore(evaluateResult.text);
			if (typeof loopEntry.score === "number") latestScore = loopEntry.score;

			const learningResult = await runManagedStage({
				cwd,
				protectedRoots: [workspace.callDir],
				modelPattern,
				thinkingLevel,
				record: loopEntry.stages.learning,
				stageName: "learning",
				loopNumber,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				relativeCallDir,
				systemPrompt: LEARNING_UPDATE_SYSTEM_PROMPT,
				userPrompt: buildLearningUpdateUserPrompt({
					cwd,
					workspace,
					loopNumber,
					requestedLoops: loops,
				}),
				manifest,
				manifestPath: workspace.rootFiles.manifest,
				onStatus,
				onEvent,
				statusMessage: `Loop ${loopNumber}/${loops}: updating LEARNING.md`,
				invocation,
			});
			const learningSections = extractMarkedSections(learningResult.text, ["LEARNING.md", "BACKLOG.md"]);
			await writeMarkdownFile(workspace.rootFiles.learning, learningSections["LEARNING.md"]);
			await writeMarkdownFile(workspace.rootFiles.backlog, learningSections["BACKLOG.md"]);
			await writeMarkdownFile(path.join(loopDir, "LEARNING.md"), learningSections["LEARNING.md"]);
			await writeMarkdownFile(path.join(loopDir, "BACKLOG.md"), learningSections["BACKLOG.md"]);

			loopEntry.completedAt = new Date().toISOString();
			manifest.completedLoops = loopNumber;
			await saveManifest(workspace.rootFiles.manifest, manifest);
			emitWorkflowEvent(onEvent, {
				type: "loop_completed",
				relativeCallDir,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
				message: `Loop ${loopNumber}/${loops} completed${typeof loopEntry.score === "number" ? ` • score ${loopEntry.score}/100` : ""}`,
				loopNumber,
				score: loopEntry.score,
			});
		}

		// === Final consolidation stages: REPORT.md and CHECKLIST.md ===
		// After all loops, generate the two final artifacts that consolidate the entire investigation.

		// C1 fix: Use manifest.report directly instead of creating a local StageRecord
		const reportResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.report,
			stageName: "report",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: REPORT_SYSTEM_PROMPT,
			userPrompt: buildReportUserPrompt({
				cwd,
				workspace,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Consolidating final report: REPORT.md`,
			invocation,
		});
		await writeMarkdownFile(workspace.rootFiles.report, reportResult.text);

		// C1 fix: Use manifest.checklist directly instead of creating a local StageRecord
		const checklistResult = await runManagedStage({
			cwd,
			protectedRoots: [workspace.callDir],
			modelPattern,
			thinkingLevel,
			record: manifest.checklist,
			stageName: "checklist",
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			relativeCallDir,
			systemPrompt: CHECKLIST_SYSTEM_PROMPT,
			userPrompt: buildChecklistUserPrompt({
				cwd,
				workspace,
				requestedLoops: loops,
				completedLoops: manifest.completedLoops,
			}),
			manifest,
			manifestPath: workspace.rootFiles.manifest,
			onStatus,
			onEvent,
			statusMessage: `Generating action checklist: CHECKLIST.md`,
			invocation,
		});
		await writeMarkdownFile(workspace.rootFiles.checklist, checklistResult.text);

		// O4 fix: workflow_completed emitted AFTER report and checklist stages complete
		manifest.status = "success";
		manifest.completedAt = new Date().toISOString();
		await saveManifest(workspace.rootFiles.manifest, manifest);
		onStatus?.(`Workflow completed in ${relativeCallDir}`);
		emitWorkflowEvent(onEvent, {
			type: "workflow_completed",
			relativeCallDir,
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			message: `Workflow completed in ${relativeCallDir}`,
			score: latestScore,
		});

		return {
			callDir: workspace.callDir,
			relativeCallDir,
			manifest,
			latestScore,
		};
	} catch (error) {
		manifest.status = "failed";
		manifest.completedAt = new Date().toISOString();
		manifest.lastError = error instanceof Error ? error.message : String(error);
		await saveManifest(workspace.rootFiles.manifest, manifest);
		onStatus?.(`Workflow failed: ${manifest.lastError}`);
		emitWorkflowEvent(onEvent, {
			type: "workflow_failed",
			relativeCallDir,
			requestedLoops: loops,
			completedLoops: manifest.completedLoops,
			message: `Workflow failed: ${manifest.lastError}`,
			isError: true,
		});
		throw error;
	}
}

import { existsSync, readFileSync } from "node:fs";
import path from "node:path";
import { isToolCallEventType, type ExtensionAPI, type ToolCallEvent } from "@mariozechner/pi-coding-agent";
import { isPathInsideRoots, parseProtectedRoots, PROTECTED_ROOTS_ENV } from "./lib/path-guards.ts";

/**
 * R1 fix: Checks if a specific root's workflow manifest is in a terminal state.
 * Only allows writes to roots whose own workflow has completed.
 */
function isRootInTerminalState(root: string): boolean {
	const manifestPath = path.join(root, "run.json");
	if (!existsSync(manifestPath)) return false;
	try {
		const manifest = JSON.parse(readFileSync(manifestPath, "utf-8"));
		return manifest.status === "success" || manifest.status === "failed";
	} catch {
		return false;
	}
}

/**
 * Finds which protected root contains the target path.
 * Returns undefined if the path is not inside any protected root.
 */
function findContainingRoot(targetPath: string, cwd: string, roots: string[]): string | undefined {
	const resolvedTarget = path.resolve(cwd, targetPath);
	return roots.find((root) => {
		const resolvedRoot = path.resolve(root);
		return resolvedTarget === resolvedRoot || resolvedTarget.startsWith(`${resolvedRoot}${path.sep}`);
	});
}

export default function artifactGuardExtension(pi: ExtensionAPI) {
	const protectedRoots = parseProtectedRoots(process.env[PROTECTED_ROOTS_ENV]);
	if (protectedRoots.length === 0) return;

	pi.on("tool_call", async (event: ToolCallEvent<"write"> | ToolCallEvent<"edit">, ctx: { cwd: string }) => {
		if (isToolCallEventType("write", event) || isToolCallEventType("edit", event)) {
			const targetPath = typeof event.input.path === "string" ? event.input.path : undefined;
			if (!targetPath) return;
			// R1 fix: Find which specific root contains this path
			const containingRoot = findContainingRoot(targetPath, ctx.cwd, protectedRoots);
			if (containingRoot) {
				// Only allow writes if THIS specific root's workflow is terminal
				if (isRootInTerminalState(containingRoot)) {
					return;
				}
				return {
					block: true,
					reason: `Artifact path is protected by the idea refinement workflow: ${targetPath}`,
				};
			}
		}
	});
}

/**
 * post-hoc-check.ts — SHA256 snapshot of the source-code directory
 *
 * Purpose: Detect whether a "develop" loop actually changed .ts files
 * in the extension directory, providing material evidence of execution
 * vs. pseudo-execution.
 *
 * Mechanism:
 * 1. Before develop: take SHA256 snapshot of all .ts files in the directory
 * 2. After develop: take a new snapshot and compare
 * 3. Returns list of changed files (or empty if none)
 *
 * This feeds criterion C7 (Material Execution) of FEEDBACK.md.
 */

import { createHash } from "node:crypto";
import { promises as fs, type Dirent } from "node:fs";
import path from "node:path";

export interface FileSnapshot {
	[relativePath: string]: string; // SHA256 hex digest
}

export interface SnapshotDiff {
	changed: string[];       // files with different hash
	added: string[];         // new files
	removed: string[];       // files that disappeared
	hasChanges: boolean;     // true if changed + added + removed > 0
}

export interface TakeSnapshotOptions {
	scope?: string[];
	maxDepth?: number;
	maxFiles?: number;
}

/**
 * Takes a SHA256 snapshot of .ts files in the extension root directory.
 * Returns a map of relative path → hash.
 * If the directory does not exist, returns an empty object.
 */
export async function takeSnapshot(extensionRoot: string, options?: TakeSnapshotOptions): Promise<FileSnapshot> {
	const snapshot: FileSnapshot = {};
	const { scope, maxDepth = Infinity, maxFiles = Infinity } = options ?? {};

	try {
		await fs.access(extensionRoot);
	} catch {
		return snapshot;
	}

	let fileCount = 0;
	let depthExceeded = false;
	let filesExceeded = false;

	async function walkDir(dir: string, depth: number): Promise<void> {
		if (depth > maxDepth) {
			depthExceeded = true;
			return;
		}
		if (fileCount >= maxFiles) {
			filesExceeded = true;
			return;
		}

		let entries: Dirent[];
		try {
			entries = await fs.readdir(dir, { withFileTypes: true });
		} catch {
			return;
		}

		for (const entry of entries) {
			if (fileCount >= maxFiles) {
				filesExceeded = true;
				return;
			}
			const fullPath = path.join(dir, entry.name);
			if (entry.isDirectory() && entry.name !== "node_modules" && !entry.name.startsWith(".")) {
				await walkDir(fullPath, depth + 1);
			} else if (entry.isFile() && entry.name.endsWith(".ts")) {
				const relPath = path.relative(extensionRoot, fullPath);
				try {
					const content = await fs.readFile(fullPath, "utf-8");
