function createMockPi() {
	const handlers: Array<{ event: string; handler: Function }> = [];
	return {
		on: (event: string, handler: Function) => {
			handlers.push({ event, handler });
		},
		handlers,
		getToolCallHandler() {
			return handlers.find((h) => h.event === "tool_call")?.handler;
		},
	};
}

